@view_public_user.route('/api/public/user/photo/<int:photo_id>', methods=['DELETE'])
@RequireLogin([User.UserStatus.REGISTER])
def delete_user_photo_by_id(photo_id):
    return response_json(objective_love_core_lib.user_photo.delete_photo_by_id(photo_id))


@view_public_user.route('/api/public/user/photo/<int:photo_type>/file', methods=['POST'])
@RequireLogin([User.UserStatus.REGISTER])
@HandleException()
def api_add_photo_file(photo_type: int):
    public_user_id = request.environ.get('user').u_id
    photo_url = request_body_dict(request).get('image_data')
    return response_json(objective_love_core_lib.user_photo.add(public_user_id, photo_url, UserPhoto.PhotoType(photo_type)))


@view_public_user.route('/api/public/user/field', methods=['PUT'])
@RequireLogin([User.UserStatus.REGISTER])
@HandleException()
def update_user_custom_field_value():
    data = request_body_dict(request)
    public_user_id = request.environ.get('user').u_id
    field = data.get('field')
    value = data.get('value')
    del data['field']
    del data['value']
    admin_core_lib.admin_field.update_target_value(public_user_id, field, value, data, None, is_updated_by_user=True)
    return response_ok()


@view_public_user.route('/api/public/user/field/all', methods=['GET'])
@RequireLogin([User.UserStatus.REGISTER])
def all_custom_fields():
    organization_id = request.environ.get('user').o_id
    meta_data = {
        CustomFieldMetaDataField.TARGET.value: FieldTarget.USER.value
    }
    custom_fields_data = admin_core_lib.admin_field.get_custom_field_context(organization_id=organization_id, meta_data=meta_data)
    return response_json(custom_fields_data)


@view_public_user.route('/api/public/user/package/all', methods=['GET'])
@RequireLogin([User.UserStatus.ACTIVE])
def all_active_packages():
    organization_id = request.environ.get('user').o_id

    packages_data = admin_core_lib.package.package.all(active=True, project_id=organization_id)
    return response_json({'packages': packages_data})

