def extract_multi_select_values(raw_value: str, options: list[str]) -> list[str]:
    if not raw_value or not options:
        return []

    normalized_option_map = {
        option.strip().lower(): option for option in options
    }

    # Work with lowercased input
    remaining = raw_value.lower()
    matched = []
    used_keys = set()

    # Sort by length desc for greedy matching
    for norm_opt in sorted(normalized_option_map.keys(), key=len, reverse=True):
        if norm_opt in remaining and norm_opt not in used_keys:
            matched.append(normalized_option_map[norm_opt])
            used_keys.add(norm_opt)
            remaining = remaining.replace(norm_opt, '', 1).strip(', ').strip()

    return matched


def parse_number_int_or_float(value):
    number = float(value)
    return int(number) if number.is_integer() else number

import datetime

from core_lib.cache.cache_decorator import Cache
from core_lib.data_layers.service.service import Service
from core_lib.data_transform.result_to_dict import ResultToDict
from core_lib.error_handling.duplicate_error_decorator import DuplicateErrorHandler
from core_lib.observer.observer_decorator import Observe
from custom_field_core_lib.constants.core_lib_constants import CACHE, CUSTOM_FIELD_CORE_LIB_NAME, PhoneNumberValueKey
from custom_field_core_lib.data_layers.data.db.entities.custom_field import CustomField
from custom_field_core_lib.data_layers.data_access.custom_field_data_access import CustomFieldDataAccess
from custom_field_core_lib.data_layers.helpers import parse_number_int_or_float
from custom_field_core_lib.data_layers.service.built_in_custom_field_service import BuiltInCustomFieldService
from custom_field_core_lib.observer.custom_field_observer_listener import CustomFieldObserverListener


class CustomFieldService(Service):
    CACHE_KEY_FIELD = 'custom_field_{id}'

    def __init__(self,
                 custom_field_data_access: CustomFieldDataAccess,
                 built_in_custom_field_service: BuiltInCustomFieldService):
        self._custom_field_data_access = custom_field_data_access
        self._built_in_custom_field_service = built_in_custom_field_service

    @Cache(CACHE_KEY_FIELD, handler_name=CACHE)
    @ResultToDict()
    def get(self, id: int):
        return self._custom_field_data_access.get(id)

    @ResultToDict()
    def all(self, project_id: int, label: str = None, type: CustomField.FieldType = None, meta_data: dict = {}, is_built_in: bool = None):
        return self._custom_field_data_access.all(project_id, label, type, meta_data, is_built_in)

    @ResultToDict()
    @DuplicateErrorHandler()
    def create_from_built_in(self, built_in_custom_field_id: int, project_id: int, meta_data: dict = {}):
        built_in_field = self._built_in_custom_field_service.get(built_in_custom_field_id)
        assert built_in_field
        new_built_in_field = self._custom_field_data_access.create({
            CustomField.label.key: built_in_field['name'],
            CustomField.project_id.key: project_id,
            CustomField.type.key: CustomField.FieldType(built_in_field['type']),
            CustomField.meta_data.key: {**built_in_field['meta_data'], **meta_data},
            CustomField.built_in_custom_field_id.key: built_in_custom_field_id,
            CustomField.built_in_custom_field_sync_time.key: datetime.datetime.utcnow(),
        })
        updated_fields = self.update_field_order(new_built_in_field.id, None)
        updated_fields[0]['is_created'] = True
        return updated_fields

    @ResultToDict()
    @DuplicateErrorHandler()
    def create(self,
               label: str,
               project_id: int,
               type: CustomField.FieldType,
               meta_data: dict = None):
        assert label and project_id and type
        new_field = self._custom_field_data_access.create({
            CustomField.label.key: label,
            CustomField.project_id.key: project_id,
            CustomField.type.key: type,
            CustomField.meta_data.key: meta_data,
            CustomField.previous_field_id.key: None,
        })
        self._fire_on_create(new_field.id, new_field.project_id)
        updated_fields = self.update_field_order(new_field.id, None)
        updated_fields[0]['is_created'] = True
        return updated_fields

    @Observe(event_key=CustomFieldObserverListener.EVENT_CUSTOM_FIELD_CREATED, observer_name=CUSTOM_FIELD_CORE_LIB_NAME)
    @ResultToDict()
    def _fire_on_create(self, id: int, project_id: int):
        pass

    @Observe(event_key=CustomFieldObserverListener.EVENT_CUSTOM_FIELD_UPDATED, observer_name=CUSTOM_FIELD_CORE_LIB_NAME)
    @ResultToDict()
    @DuplicateErrorHandler()
    def update(self,
               custom_field_id: int,
               label: str,
               type: CustomField.FieldType,
               meta_data=None,
               built_in_custom_field_sync_time: datetime.datetime = None,
               previous_field_id: int = None):
        update_data = {
            CustomField.label.key: label,
            CustomField.type.key: type,
            CustomField.meta_data.key: meta_data,
        }
        if built_in_custom_field_sync_time:
            update_data[CustomField.built_in_custom_field_sync_time.key] = built_in_custom_field_sync_time

        if previous_field_id:
            update_data[CustomField.previous_field_id.key] = previous_field_id

        self._custom_field_data_access.update(custom_field_id, update_data)
        self._invalidate_field_id_cache(custom_field_id)
        return [self.get(custom_field_id)]

    @Observe(event_key=CustomFieldObserverListener.EVENT_CUSTOM_FIELD_UPDATED, observer_name=CUSTOM_FIELD_CORE_LIB_NAME)
    @ResultToDict()
    @DuplicateErrorHandler()
    def update_by_data(self, custom_field_id: int, data: dict):
        self._custom_field_data_access.update(custom_field_id, data)
        self._invalidate_field_id_cache(custom_field_id)
        return self.get(custom_field_id)

    @Cache(CACHE_KEY_FIELD, invalidate=True, handler_name=CACHE)
    def delete(self, id: int):
        current_field = self.get(id)
        project_id = current_field[CustomField.project_id.key]
        previous_field_id = current_field[CustomField.previous_field_id.key]
        next_field = self._custom_field_data_access.get_next_field(project_id, id)
        if next_field:
            self._custom_field_data_access.update(
                next_field.id,
                {CustomField.previous_field_id.key: previous_field_id}
            )
            self._invalidate_field_id_cache(next_field.id)
        self._fire_on_delete(current_field[CustomField.id.key], current_field[CustomField.project_id.key])
        return self._custom_field_data_access.delete(id)

    @Observe(event_key=CustomFieldObserverListener.EVENT_CUSTOM_FIELD_DELETED, observer_name=CUSTOM_FIELD_CORE_LIB_NAME)
    def _fire_on_delete(self, id: int, project_id: int):
        pass

    @ResultToDict()
    def all_missing(self, target_id: int, project_id: int, meta_data: dict = None, target_meta_data: dict = None):
        return self._custom_field_data_access.all_missing(target_id, project_id, meta_data, target_meta_data)

    @ResultToDict()
    def get_target_fields(self, target_id: int, project_id: int, meta_data: dict = None, target_meta_data: dict = None):
        return self._custom_field_data_access.get_target_fields(target_id, project_id, meta_data, target_meta_data)

    @ResultToDict()
    def get_target_value_by_custom_field_id(self, target_id: int, custom_field_id: int):
        return self._custom_field_data_access.get_target_value_by_custom_field_id(target_id, custom_field_id)

    @ResultToDict()
    def update_target_value(self, target_id: int, field_id: int, value, update_history_meta_data: dict = {}, filter_target_meta_data: dict = {}, update_target_meta_data: dict = {}):
        value = self._handle_empty_values(value)
        if value is not None:
            value = self._convert_and_validate_value(field_id, value)
            return self._custom_field_data_access.update_target_value(target_id, field_id, value, update_history_meta_data, filter_target_meta_data, update_target_meta_data)
        else:
            return self._custom_field_data_access.delete_target_value(target_id, field_id, update_history_meta_data, filter_target_meta_data, update_target_meta_data)

    @ResultToDict()
    def get_all_fields_pending_update(self):
        return self._custom_field_data_access.get_all_fields_pending_update()

    @ResultToDict()
    def update_field_order(self, field_id: int, new_previous_field_id: int):
        assert field_id
        current_field = self.get(field_id)
        project_id = current_field[CustomField.project_id.key]
        field_below_the_current_field_after_move = self._custom_field_data_access.get_next_field(project_id, new_previous_field_id, field_id)
        field_below_the_current_field_before_move = self._custom_field_data_access.get_next_field(project_id, field_id)
        updated_fields = []
        self._custom_field_data_access.update(field_id, {CustomField.previous_field_id.key: new_previous_field_id})
        self._invalidate_field_id_cache(field_id)
        updated_fields.append(self.get(field_id))
        if field_below_the_current_field_after_move:
            self._custom_field_data_access.update(field_below_the_current_field_after_move.id, {CustomField.previous_field_id.key: field_id})
            self._invalidate_field_id_cache(field_below_the_current_field_after_move.id)
            updated_fields.append(self.get(field_below_the_current_field_after_move.id))
        if field_below_the_current_field_before_move:
            self._custom_field_data_access.update(field_below_the_current_field_before_move.id, {CustomField.previous_field_id.key: current_field[CustomField.previous_field_id.key]})
            self._invalidate_field_id_cache(field_below_the_current_field_before_move.id)
            updated_fields.append(self.get(field_below_the_current_field_before_move.id))
        return updated_fields

    @Cache(CACHE_KEY_FIELD, invalidate=True, handler_name=CACHE)
    def _invalidate_field_id_cache(self, id: int):
        pass

    def _handle_empty_values(self, value):
        if value is None:
            return None
        if isinstance(value, str) and value.strip() == "":
            return None
        if isinstance(value, (list, tuple, set)) and len(value) == 0:
            return None
        if isinstance(value, dict) and not value:
            return None
        return value

    def _convert_and_validate_value(self, field_id: int, value):
        if value is not None:
            custom_field = self.get(field_id)
            field_type = custom_field[CustomField.type.key]
            if field_type == CustomField.FieldType.NUMBER.value and value:
                value = parse_number_int_or_float(value)
                assert type(value) == int or type(value) == float
            elif field_type == CustomField.FieldType.YES_NO.value or field_type == CustomField.FieldType.VIDEO.value:
                assert type(value) == bool
            elif field_type == CustomField.FieldType.DATE.value:
                assert type(value) == int
            elif field_type == CustomField.FieldType.ADDRESS.value:
                assert type(value) == dict
            elif field_type == CustomField.FieldType.MULTI_SELECT.value:
                assert type(value) == list
            elif field_type == CustomField.FieldType.PHONE_NUMBER.value:
                assert type(value) == dict
                assert PhoneNumberValueKey.COUNTRY_CODE.value in value
                assert PhoneNumberValueKey.NUMBER.value in value
            else:
                assert type(value) == str
        return value

