import Network from './network';

Network.registerModule('fields', function (network) {
  return {
    all: function (data, success, error) {
      network.post(`api/field/all`, data, {}, success, error);
    },
    get: function (field_id, is_user_field, success, error) {
      network.post(`api/field/${field_id}`, { is_user_field }, {}, success, error);
    },
    create: function (data, success, error) {
      network.post('api/field', data, {}, success, error);
    },
    create_built_in: function (data, success, error) {
      network.post('api/field/built_in', data, {}, success, error);
    },
    update_definition: function (customFieldId, data, success, error) {
      network.put(`api/field/${customFieldId}`, data, {}, success, error);
    },
    update_single_field: function (customFieldId, data, success, error) {
      network.put(`api/field/single_field/${customFieldId}`, data, {}, success, error);
    },
    update_user_value: function (userId, field, value, target_type, meta_data, success, error) {
      network.put(`api/field/user/${userId}`, {field, value, target_type, meta_data}, {}, success, error);
    },
    delete: function (customFieldId, success, error) {
      network.del(`api/field/${customFieldId}`, {}, {}, success, error);
    },
    updateOrder: function (custom_field_id, new_previous_custom_field_id, success, error) {
      network.put(`api/field/order/${custom_field_id}`, {new_previous_custom_field_id}, {}, success, error);
    },
    getAllCategories: function (success, error) {
      network.get(`api/field/category/all`, {}, {}, success, error);
    },
  };
});

