import create from 'zustand';
// eslint-disable-next-line no-unused-vars
import networkPublicFields from '../../networkPublic/networkPublicFields';
import NetworkPublic from '../../networkPublic/networkPublic';
import { useNotificationSystemStore } from '../notificationSystem/notificationSystemStore';
import i18n from '../../i18n';
import { NOTIFICATION_SEVERITIES } from '../../constants';
import { usePublicProfileStore } from '../publicProfile/publicProfileStore';
import { createCustomFieldIdToValueMapping } from '../../components/CustomField/helpers';

export const usePublicFieldsStore = create((set, get) => ({
    isLoading: false,
    fieldsData: [],
    builtInCustomFields: [],
    fieldIdToValueMapping: {},
    get: () => {
        set(() => ({ isLoading: true }));
        NetworkPublic.fields.get(
            (data) => {
                set(() => ({
                    fieldsData: data.organization_custom_fields || [],
                    builtInCustomFields: data.built_in_custom_fields || [],
                    isLoading: false,
                    fieldIdToValueMapping: createCustomFieldIdToValueMapping(data.organization_custom_fields),
                }));
            },
            (err) => {
                set(() => ({ isLoading: false }));
            },
        );
    },
    updateUserValue: (field, value, metaData, successCallback = () => { }) => {
        NetworkPublic.fields.updateUserValue(
            field,
            value,
            metaData,
            (updatedField) => { 
                usePublicProfileStore.getState().fetchProfileEdit(false);
                successCallback() 
            },
            (err) => {
                useNotificationSystemStore.getState().message(i18n.t('pages.error'), NOTIFICATION_SEVERITIES.ERROR);
            }
        );
    },
}));

