import { useEffect } from "react"
import { useParams } from "react-router-dom";

import './PublicUserProfile.scss';
import { usePublicProfileStore } from "../../store/publicProfile/publicProfileStore";
import NetworkPublic from '../../networkPublic/networkPublic';
import { usePublicFieldsStore } from "../../store/publicFields/publicFieldsStore";
import { useOrganizationStore } from "../../store/organization/organizationStore";
import PublicUserProfile from "./PublicUserProfile";
import { usePublicPackageStore } from "../../store/publicPackage/publicPackageStore";
import { usePublicSearchEngineStore } from "../../store/publicSearchEngine/publicSearchEngineStore";
import { showAskMatchesMessage, showProfileExternal } from "../../components/search/windowHelpers";
import { useSystemStore } from "../../store/system/systemStore";
import { getFieldUpdateSuccessMessage, getIsUserField } from "../../components/CustomField/helpers";
import { useNotificationSystemStore } from "../../store/notificationSystem/notificationSystemStore";
import { NOTIFICATION_SEVERITIES, USER_ENTITY_FIELDS } from "../../constants";
import { getDateFromTimestamp } from '@ob-love/ui';

const PublicUserProfileEdit = () => {
    const publicProfileStore = usePublicProfileStore(state => state);
    const publicFieldsStore = usePublicFieldsStore(state => state);
    const publicPackageStore = usePublicPackageStore((state) => state);
    const publicSearchEngineStore = usePublicSearchEngineStore(state => state);
    const organizationStore = useOrganizationStore((state) => state);
    const systemStore = useSystemStore(state => state);

    const { organization_code } = useParams();

    const isUserStatusActive = publicProfileStore.publicUserProfile?.information?.status && 
        systemStore.constants.user_status.ACTIVE && 
        publicProfileStore.publicUserProfile.information.status === systemStore.constants.user_status.ACTIVE;

    useEffect(() => {
        if(
            organizationStore.organizationDetails.is_show_introduction_on_public_page && 
            isUserStatusActive
        ) {
            publicSearchEngineStore.search();
        }
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [organizationStore.organizationDetails.is_show_introduction_on_public_page, isUserStatusActive])

    useEffect(() => {
        if (isUserStatusActive) {
            publicPackageStore.get();
        }
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [isUserStatusActive]);

    useEffect(() => {
        if (organization_code) {
            organizationStore.getOrganizationByCode(organization_code);
        }
        publicFieldsStore.get();
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [])

    const updateUserField = (field, value,  metaData = {}) => {
        const isUserField = getIsUserField(field);
        if (isUserField) {
            if (field === USER_ENTITY_FIELDS.BIRTHDAY) {
                value = getDateFromTimestamp(value)
            }
        }
        publicFieldsStore.updateUserValue(
            field, 
            value,
            metaData, 
            () => {
                usePublicProfileStore.getState().fetchProfileEdit(false);
                const successMessage = getFieldUpdateSuccessMessage(field, usePublicFieldsStore.getState().fieldIdToValueMapping);
                useNotificationSystemStore.getState().message(successMessage, NOTIFICATION_SEVERITIES.SUCCESS);
            }
        );
    }

    const performPhotoUpload = (photoType) => {
        const img = new Image();
        img.onload = function () {
            const reader = new FileReader();
            reader.onload = (e) => {
                const imageData = e.target.result;
                NetworkPublic.profile.addUserPhoto(
                    photoType,
                    imageData,
                    (res) => {
                        usePublicProfileStore.getState().addUserPhoto(null);
                        usePublicProfileStore.getState().fetchProfileEdit();
                    },
                    (err) => { }
                )
            };
            reader.readAsDataURL(usePublicProfileStore.getState().userImgToUpload);
        };
        img.src = URL.createObjectURL(usePublicProfileStore.getState().userImgToUpload);
    }

    const onNextExternal = () => {
        publicSearchEngineStore.nextExternal(() => {
            if (publicSearchEngineStore.profiles_external.length > 0) {
                showProfileExternal();
            }
        });
    }

    const onNextExternalUnilateral = () => {
        publicSearchEngineStore.nextExternalUnilateral(() => {
            if (publicSearchEngineStore.profiles_external_unilateral.length > 0) {
                showProfileExternal(true);
            }
        });
    }

    const onAskMatches = () => {
        showAskMatchesMessage();
    }

    let renderContent = ( 
        <PublicUserProfile
            isEdit={true}
            onPhotoUpload={performPhotoUpload}
            updateUserField={updateUserField}
            isEditDataLoading={publicFieldsStore.isLoading || publicPackageStore.isLoading}
            isPublicEdit={true}
            onNextExternal={onNextExternal}
            onAskMatches={onAskMatches}
            onNextExternalUnilateral={onNextExternalUnilateral}
            // showPackages={isUserStatusActive} // DISABLED UNTILL PAYMENT IS FINALIZED
            showPackages={false}
            showSearchEngine={
                (
                    organizationStore.organizationDetails?.is_show_introduction_on_public_page ||
                    organizationStore.organizationDetails?.allow_match_external ||
                    organizationStore.organizationDetails?.allow_match_unilateral
                ) &&
                isUserStatusActive && 
                !publicProfileStore.publicUserProfile?.information?.conversation_id 
            }
        />
    )
    return renderContent;
}

export default PublicUserProfileEdit;

