3	
4	import './EditableCustomField.scss';
5	import { useSystemStore } from '../../../store/system/systemStore';
6	import i18n from '../../../i18n';
7	import { EditableDropdown } from "@ob-love/ui";
8	import { EditableTextfield } from "@ob-love/ui";
9	import { getTextFieldTypeByCustomFieldType } from '../../../store/system/helpers';
10	import { convertIconFormatFromDB, getOptionsYesNo } from '../../../helpers';
11	import EditableDate from '../../EditableDate/EditableDate';
12	import { buildCustomFieldDropdownColorOptions } from '../helpers';
13	import { buildAddressCustomFieldValue, convertYesNoValueToBoolean } from '../../CustomField/helpers';
14	
15	const EditableCustomField = (props) => {
16	    const systemConstants = useSystemStore((state) => state.constants);
17	    const isMultiSelect = props.type === systemConstants.field_type.MULTI_SELECT;
18	    const [isEdit, setIsEdit] = useState(false);
19	    const [value, setValue] = useState(isMultiSelect ? props.value || [] : props.value);
20	
21	    const isBuiltInField = !!props.built_in_custom_field_id;
22	    const isDropDown = systemConstants.field_type.DROPDOWN === props.type;
23	    let fieldValue = isBuiltInField && isDropDown ? i18n.t(`customFields.${value}`, {defaultValue: ''}) : value;
24	
25	    const onSubmit = (e) => {
26	        e && e.preventDefault();
27	        let _value = value;
28	    
29	        if (_value !== props.value) {
30	            let meta_data = {};
31	    
32	            if (props.type === systemConstants.field_type.DROPDOWN || props.type === systemConstants.field_type.MULTI_SELECT) {
33	                meta_data = buildCustomFieldDropdownColorOptions(value, props.dropDownOptions, props.dropdownColorOptions);
34	            }
35	    
36	            props.onEdit(props.id, _value, () => {}, () => { setValue(props.value) }, meta_data);
37	        }
38	    
39	        setIsEdit(!isEdit);
40	    };
41	
42	    const getCustomFieldEditInput = () => {
43	        const fieldType = getTextFieldTypeByCustomFieldType(props.type);
44	        if(fieldType !== null) {
45	            const isAddress = props.type === systemConstants.field_type.ADDRESS;
46	            const placeholder = props.placeholder ? i18n.t(props.placeholder) : i18n.t('users.customFieldNotFilled');
47	            if (isAddress && fieldValue) {
48	                fieldValue = buildAddressCustomFieldValue(fieldValue);
49	            }
50	            return (
51	                <form onSubmit={onSubmit}>
52	                    <EditableTextfield
53	                        key={`cf_edit_${props.id}`}
54	                        placeholder={placeholder}
55	                        type={fieldType}
56	                        defaultValue={fieldValue ? fieldValue : ''}
57	                        value={fieldValue ? fieldValue : ''}
58	                        onBlur={onSubmit}
59	                        onChange={(e) => {
60	                            setValue(e.target.value)}
61	                        }
62	                        multiline={true}
63	                        maxRows={10}
64	                        disabled={!props.isEdit || isAddress}
65	                        showBigEditIcon={props.showBigEditIcon}
66	                    />
67	                </form>
68	            )
69	        } else if (
70	            props.type === systemConstants.field_type.DROPDOWN || 
71	            props.type === systemConstants.field_type.MULTI_SELECT ||
72	            props.type === systemConstants.field_type.YES_NO
73	        ) {
74	            let options = [];
75	            let displayConstantPropsValue = !props.isEdit;
76	            if (props.type === systemConstants.field_type.YES_NO) {
77	                options = getOptionsYesNo('name')
78	                fieldValue = convertYesNoValueToBoolean(value);
79	                displayConstantPropsValue = false;
80	            } else {
81	                options = props.dropDownOptions.map(option => ({value: option, name: option}))
82	            }
83	            const placeholder = props.placeholder ? props.placeholder : i18n.t('users.customFieldNotFilled');
84	            return (
85	                <EditableDropdown
86	                    placeholder={placeholder}
87	                    defaultValue={fieldValue}
88	                    value={fieldValue}
89	                    options={options}
90	                    onChange={(e) => {setValue(e.target.value)}}
91	                    onBlur={onSubmit}
92	                    disabled={!props.isEdit}
93	                    displayConstantPropsValue={displayConstantPropsValue}
94	                    multiple={props.type === systemConstants.field_type.MULTI_SELECT}
95	                    showBigEditIcon={props.showBigEditIcon}
96	                />
97	            );
98	        } else if (props.type === systemConstants.field_type.DATE) {
99	            const _value = value ? parseInt(value) : null;
100	            const placeholder = props.placeholder ? props.placeholder : i18n.t('users.customFieldNotFilled');
101	            return (
102	                <EditableDate
103	                    placeholder={placeholder}
104	                    defaultValue={_value}
105	                    value={_value}
106	                    onChange={(value) => {
107	                        setValue(value);
108	                        props.onEdit(props.id, value, () => {}, () => {setValue(props.value)})
109	                    }}
110	                    disabled={!props.isEdit}
111	                    showBigEditIcon={props.showBigEditIcon}
112	                />
113	            );
114	        }
115	    }
116	
117	    return (
118	        <div  className='editable-custom-field'>
