import { useSystemStore } from "./systemStore";

export const convertModulesToInt = (modules = {}) => {
    return Object.keys(modules).map(module => parseInt(module));
}

export const getTextFieldTypeByCustomFieldType = (type) => {
    const fieldType = useSystemStore.getState().constants.field_type;
    if (fieldType) {
        switch (type) {
            case fieldType.TEXT:
                return 'text';
            case fieldType.NUMBER:
                return 'number';
            case fieldType.TEXT_AREA:
                return 'text_area';
            case fieldType.ADDRESS:
                return 'address';
            case fieldType.PHONE_NUMBER:
                return 'text';
            default:
                return null;
        }
    }
};

