import UserDetailsPanel from "../UserDetailsPanel/UserDetailsPanel";
import { useLocalStorageStore } from '../../../store/localStorage/localStorageStore';
import './UserCategoryView.scss'

const UserCategoryView = (props) => {
    const panels = props.subCategories.map((subCategory, index) => {
        const accordionKey = `${props.categoryKey}_${index}`;
        const savedState = useLocalStorageStore.getState().getAccordionState(accordionKey);
        const initialExpanded = savedState !== undefined ? savedState : true;
        return (
            <UserDetailsPanel
                key={`subcat_${props.categoryKey}_${index}`}
                title={subCategory.label}
                fieldsData={subCategory.fields}
                onEdit={props.onEdit}
                categoryKey={props.categoryKey}
                subCategoryIndex={index}
                categoryMenuItems={props.categoryMenuItems}
                categorySubCategoryMenuItems={props.categorySubCategoryMenuItems}
                isShowMenu={props.isShowMenu}
                isDragDropEnabled={props.isDragDropEnabled}
                isFieldsDisabled={props.isFieldsDisabled}
                disabledTextColor={props.disabledTextColor}
                isAccordionDisabled={props.isAccordionDisabled}
                initialExpanded={initialExpanded}
                isShowSearchable={props.isShowSearchable}
            />
        )
    })
    return (
        <div className='user-category-view-wrap'>
            {panels}
        </div>
    )
}

export default UserCategoryView;

UserCategoryView.defaultProps = {
    categoryKey: '',
    subCategories: [],
    categoryMenuItems: [],
    categorySubCategoryMenuItems: [],
    isShowMenu: false,
    isDragDropEnabled: false,
    isFieldsDisabled: false,
    disabledTextColor: undefined,
    isAccordionDisabled: false,
    isShowSearchable: true,
    onEdit: () => {},
}

