import { useEffect, useRef, useState } from 'react';
import './UserDetailsPanel.scss';
import { Draggable, Droppable } from 'react-beautiful-dnd';

import i18n from '../../../i18n';
import Accordion from '@mui/material/Accordion';
import AccordionSummary from '@mui/material/AccordionSummary';
import AccordionDetails from '@mui/material/AccordionDetails';
import EditableUserField from '../EditableUserField/EditableUserField';
import KeyboardArrowDownIcon from '@mui/icons-material/KeyboardArrowDown';
import { MODULE, SMALL_SCREEN_BREAKPOINT } from '../../../constants';
import { MoreVert } from '@mui/icons-material';
import DragIndicatorIcon from '@mui/icons-material/DragIndicator';
import IconMenu from '../../IconMenu/IconMenu';
import ValueContent from './ValueContent';
import { useLocalStorageStore } from '../../../store/localStorage/localStorageStore';
import { useUiSettingsStore } from '../../../store/uiSettings/uiSettingsStore';
import SearchableIcon from '../../../assets/icons/SearchableIcon';
import { buildSearchableFieldMenuItems, isFieldSearchable } from '../../../store/uiSettings/helpers';
import CopyableText from '../../CopyableText/CopyableText';


const UserDetailsPanel = (props) => {
    const containerRef = useRef(null);
    const [isSmallScreen, setIsSmallScreen] = useState(false);
    const [isAccordionExpanded, setIsAccordionExpanded] = useState(props.initialExpanded);

    const localStorageStore = useLocalStorageStore((state) => state);
    const searchableFields = useUiSettingsStore((state) => state.uiSettings?.[MODULE.USER]?.profileCard?.searchableFields) || {};

    const accordionKey = `${props.categoryKey}_${props.subCategoryIndex}`;

    useEffect(() => {
        const element = containerRef.current;
        if (!element) return;

        const resizeObserver = new ResizeObserver(() => {
            const width = containerRef.current.offsetWidth;
            setIsSmallScreen(width < SMALL_SCREEN_BREAKPOINT);
        });

        resizeObserver.observe(element);

        return () => resizeObserver.disconnect();
    }, []);

    const onEdit = (field, value, metaData, successCallback, errorCallback) => {
        props.onEdit(field, value, metaData, successCallback, errorCallback);
    }

    const fields = props.fieldsData.map((field, index) => {
        let valueContent;
        if (field.isDisplayOnly) {
            valueContent = field.isCopyable
                ? <CopyableText copyValue={field.copyValue}>{field.value}</CopyableText>
                : field.value;
        } else {
            valueContent = (
                <EditableUserField
                    name={field.name}
                    value={field.value}
                    type={field.type}
                    icon={field.icon}
                    field={field.field}
                    built_in_custom_field_id={field.built_in_custom_field_id}
                    onEdit={onEdit}
                    options={field.options}
                    optionColors={field.optionColors}
                    isEdit={field.isEdit && !props.isFieldsDisabled}
                    showBigEditIcon={props.showBigEditIcon}
                    placeholder={field.placeholder}
                    prefix={field.prefix}
                    suffix={field.suffix}
                    showToday={field.showToday}
                    disabledTextColor={props.disabledTextColor}
                    isFirstNameVisible={field.isFirstNameVisible}
                    isMiddleNameVisible={field.isMiddleNameVisible}
                    isLastNameVisible={field.isLastNameVisible}
                    isFirstNameEdit={field.isFirstNameEdit}
                    isMiddleNameEdit={field.isMiddleNameEdit}
                    isLastNameEdit={field.isLastNameEdit}
                />
            )
        }
        const fieldMenuItems = [
            ...(props.categorySubCategoryMenuItems || []),
            ...buildSearchableFieldMenuItems(field, searchableFields),
        ];
        const renderMenu = props.isShowMenu && (
            <IconMenu
                icon={<MoreVert fontSize='inherit' />}
                menuItems={fieldMenuItems}
                anchorOriginVertical='-10'
                clickParams={{
                    categoryKey: props.categoryKey,
                    subCategoryIndex: props.subCategoryIndex,
                    field:field.field
                }}
            />
        )

        const showSearchableIcon = props.isShowSearchable && isFieldSearchable(field, searchableFields);
        const searchableIconElement = showSearchableIcon && (
            <SearchableIcon className='searchable-icon' fontSize='inherit' />
        );

        const draggableId = `field_${props.categoryKey}_${props.subCategoryIndex}_${index}`;
        const renderFieldContent = (dragHandleProps = null) => {
            const dragHandle = dragHandleProps && (
                <div className='drag-handle' {...dragHandleProps}>
                    <DragIndicatorIcon fontSize='small' />
                </div>
            )
            return (
                <div ref={containerRef} className={`user-details-content-wrap`} key={`field_${field.field}`}>
                    {dragHandle}
                    <div className={`user-details-content ${isSmallScreen ? 'small' : ''}`}>

                        <div className={`name ${isSmallScreen ? 'small' : ''}`}>
                            {i18n.t(field.name)}
                        </div>
                        <ValueContent
                            className={`value ${field.className} ${field.isDisplayOnly ? 'display-only' : ''}`}
                            content={valueContent}
                            isEditable={!field.isDisplayOnly || field.isEdit}
                            style={{color: field.isEdit || !field.isDisplayOnly ? 'inherit' : props.disabledTextColor}}
                        />
                    </div>
                    <div className='user-details-menu-wrap'>
                        {searchableIconElement}

