20	    const isMultiSelect = props.type === systemConstants.field_type.MULTI_SELECT;
21	    const isUserName = props.type === USER_NAME_FIELD;
22	    const [isEdit, setIsEdit] = useState(false);
23	    const [value, setValue] = useState(isMultiSelect ? props.value || [] : props.value);
24	    const valueRef = useRef(value);
25	
26	    useEffect(() => { 
27	        valueRef.current = value;
28	        // eslint-disable-next-line react-hooks/exhaustive-deps
29	    }, [value]);
30	
31	    useEffect(() => {
32	        let _value = props.value;
33	        if (isMultiSelect) {
34	            _value = props.value || [];
35	        }
36	        if (isUserName) {
37	            _value = props.value || {};
38	        }
39	        setValue(_value);
