52	
53	            if (props.type === systemConstants.field_type.DROPDOWN || props.type === systemConstants.field_type.MULTI_SELECT) {
54	                meta_data = buildCustomFieldDropdownColorOptions(_value, props.options, props.optionColors);
55	            }
56	
57	            props.onEdit(props.field, _value, meta_data, () => { }, () => { setValue(props.value) });
58	        }
59	
60	        setIsEdit(!isEdit);
61	    };
62	    const getCustomFieldEditInput = () => {
63	        const fieldType = getTextFieldTypeByCustomFieldType(props.type);
64	        if (fieldType !== null) {
65	            const isAddress = props.type === systemConstants.field_type.ADDRESS;
66	            const instructions = props.placeholder ? i18n.t(props.placeholder) : i18n.t('users.customFieldNotFilled');
67	            if (isAddress) {
68	            return (
69	                <EditableAddress
70	                    key={`field_${props.field}`}
71	                    street_address={fieldValue?.street_address}
72	                    city={fieldValue?.city}
73	                    state={fieldValue?.state}
74	                    country={fieldValue?.country}
75	                    zip_code={fieldValue?.zip_code}
76	                    onBlur={onSubmit}
77	                    disabled={!props.isEdit}
78	                    disabledTextColor={props.disabledTextColor}
79	                    editIcon={props.editIcon}
80	                    onChange={
81	                        (e) => {
82	                            setValue(prevValue => {
83	                                return {
84	                                    ...prevValue,
85	                                    [e.target.name]: e.target.value,
86	                                }
87	                            })
88	                        }
89	                    }
90	                />
91	            )
92	            }
93	            if (props.type === systemConstants.field_type.PHONE_NUMBER) {
94	                return <EditablePhoneNumber
95	                    key={`cf_edit_${props.field}`}
96	                    placeholder={props.placeholder}
97	                    value={fieldValue}
98	                    onBlur={onSubmit}
99	                    disabled={!props.isEdit}
100	                    disabledTextColor={props.disabledTextColor}
101	                    editIcon={props.editIcon}
102	                    onChange={
103	                        (value) => {
104	                            setValue(value)
105	                        }
