import React, { useEffect, useRef, useState } from 'react';

import './EditableUserField.scss';
import { useSystemStore } from '../../../store/system/systemStore';
import i18n from '../../../i18n';
import { EditableDropdown } from "@ob-love/ui";
import { EditableTextfield } from "@ob-love/ui";
import { getTextFieldTypeByCustomFieldType } from '../../../store/system/helpers';
import { convertToMoment, getNullDropdownOption, getOptionsYesNo } from '../../../helpers';
import EditableDate from '../../EditableDate/EditableDate';
import { convertYesNoValueToBoolean } from '../../CustomField/helpers';
import { buildCustomFieldDropdownColorOptions } from '../../userInfoBigCard/helpers';
import EditableUserName from '../../EditableUserName/EditableUserName';
import { USER_NAME_FIELD } from '../fieldRegistry';
import { EditableAddress } from "@ob-love/ui";
import { EditablePhoneNumber } from "@ob-love/ui";

const EditableUserField = (props) => {
    const systemConstants = useSystemStore.getState().constants;
    const isMultiSelect = props.type === systemConstants.field_type.MULTI_SELECT;
    const isUserName = props.type === USER_NAME_FIELD;
    const [isEdit, setIsEdit] = useState(false);
    const [value, setValue] = useState(isMultiSelect ? props.value || [] : props.value);
    const valueRef = useRef(value);

    useEffect(() => { 
        valueRef.current = value;
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [value]);

    useEffect(() => {
        let _value = props.value;
        if (isMultiSelect) {
            _value = props.value || [];
        }
        if (isUserName) {
            _value = props.value || {};
        }
        setValue(_value);
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [props.value, isMultiSelect, isUserName]);

    const isBuiltInCustomField = !!props.built_in_custom_field_id;
    const isDropDown = systemConstants.field_type.DROPDOWN === props.type;
    let fieldValue = isBuiltInCustomField && isDropDown ? i18n.t(`customFields.${value}`, { defaultValue: '' }) : value;

    const onSubmit = (e) => {
        e && e.preventDefault();
        let _value = valueRef.current;
        if (_value !== props.value) {
            let meta_data = {};

            if (props.type === systemConstants.field_type.DROPDOWN || props.type === systemConstants.field_type.MULTI_SELECT) {
                meta_data = buildCustomFieldDropdownColorOptions(_value, props.options, props.optionColors);
            }

            props.onEdit(props.field, _value, meta_data, () => { }, () => { setValue(props.value) });
        }

        setIsEdit(!isEdit);
    };
    const getCustomFieldEditInput = () => {
        const fieldType = getTextFieldTypeByCustomFieldType(props.type);
        if (fieldType !== null) {
            const isAddress = props.type === systemConstants.field_type.ADDRESS;
            const instructions = props.placeholder ? i18n.t(props.placeholder) : i18n.t('users.customFieldNotFilled');
            if (isAddress) {
            return (
                <EditableAddress
                    key={`field_${props.field}`}
                    street_address={fieldValue?.street_address}
                    city={fieldValue?.city}
                    state={fieldValue?.state}
                    country={fieldValue?.country}
                    zip_code={fieldValue?.zip_code}
                    onBlur={onSubmit}
                    disabled={!props.isEdit}
                    disabledTextColor={props.disabledTextColor}
                    editIcon={props.editIcon}
                    onChange={
                        (e) => {
                            setValue(prevValue => {
                                return {
                                    ...prevValue,
                                    [e.target.name]: e.target.value,
                                }
                            })
                        }
                    }
                />
            )
            }
            if (props.type === systemConstants.field_type.PHONE_NUMBER) {
                return <EditablePhoneNumber
                    key={`cf_edit_${props.field}`}
                    placeholder={props.placeholder}
                    value={fieldValue}
                    onBlur={onSubmit}
                    disabled={!props.isEdit}
                    disabledTextColor={props.disabledTextColor}
                    editIcon={props.editIcon}
                    onChange={
                        (value) => {
                            setValue(value)
                        }
                    }
                    showBigEditIcon={props.showBigEditIcon}
                />
            }
            return (
                <form onSubmit={onSubmit}>
                    <EditableTextfield
                        variant={'outlined'}
                        key={`cf_edit_${props.field}`}
                        placeholder={instructions}
                        type={fieldType}
                        defaultValue={fieldValue ? fieldValue : ''}
                        value={fieldValue ? fieldValue : ''}
                        onBlur={onSubmit}
                        disabledTextColor={props.disabledTextColor}
                        editIcon={props.editIcon}
                        onChange={
                            (e) => {
                                setValue(e.target.value)
                            }
                        }
                        multiline={true}
                        maxRows={10}
                        disabled={!props.isEdit || isAddress}
                        showBigEditIcon={props.showBigEditIcon}
                    />
                </form>
            )
        } else if (
            props.type === systemConstants.field_type.DROPDOWN ||
            props.type === systemConstants.field_type.MULTI_SELECT ||
            props.type === systemConstants.field_type.YES_NO
        ) {
            let options = [];
            if (props.type === systemConstants.field_type.YES_NO) {
                options = getOptionsYesNo('name')
                fieldValue = convertYesNoValueToBoolean(value);
            } else {
                options = props.options.map(option => {
                    if (typeof option === 'object') {
                        return option
                    } else {
                        return { value: option, name: option }
                    }
                })
            }
            if (props.isEdit && props.type === systemConstants.field_type.DROPDOWN) {
                options.unshift(getNullDropdownOption())
            }
            const displayConstantPropsValue = !props.isEdit && options.length === 0;
            const instructions = props.placeholder ? props.placeholder : i18n.t('users.customFieldNotFilled');
            return (
                <EditableDropdown
                    variant={'outlined'}
                    placeholder={instructions}
                    defaultValue={fieldValue}
                    value={fieldValue}
                    options={options}
                    onChange={(e) => {setValue(e.target.value) }}
                    onBlur={onSubmit}
                    displayConstantPropsValue={displayConstantPropsValue}
                    disabled={!props.isEdit}
                    disabledTextColor={props.disabledTextColor}
                    editIcon={props.editIcon}
                    multiple={props.type === systemConstants.field_type.MULTI_SELECT}
                    showBigEditIcon={props.showBigEditIcon}
                    showIconOnEmptyValues={false}
                    suffix={props.suffix}
                />
            );
        } else if (props.type === systemConstants.field_type.DATE) {
            // Backend may return ISO date strings ("2026-04-22") or Unix seconds; EditableDate expects Unix seconds.
            let _value = null;
            if (value) {
                const normalized = typeof value === 'string' && /^\d+$/.test(value) ? parseInt(value, 10) : value;
                const dateMoment = convertToMoment(normalized);
                _value = dateMoment ? dateMoment.unix() : null;
            }
            const instructions = props.placeholder ? props.placeholder : i18n.t('users.customFieldNotFilled');
            return (
                <EditableDate
                    placeholder={instructions}
                    defaultValue={_value}
                    value={_value}
                    onChange={(value) => {
                        setValue(value);
                        props.onEdit(props.field, value, {}, () => { }, () => { setValue(props.value) })
                    }}
                    disabled={!props.isEdit}
                    disabledTextColor={props.disabledTextColor}
                    editIcon={props.editIcon}
                    showBigEditIcon={props.showBigEditIcon}
                    showToday={props.showToday}
                    suffix={props.suffix}
                />
            );
        } else if (isUserName) {
            return <EditableUserName
                variant={'outlined'}
                key={`cf_edit_${props.field}`}
                placeholder={props.placeholder}
                value={fieldValue}
                onBlur={onSubmit}
                disabled={!props.isEdit}
                disabledTextColor={props.disabledTextColor}
                editIcon={props.editIcon}
                onChange={
                    (e) => {
                        setValue(prevState => {
                            return { ...{
                                ...prevState,
                                [e.target.name]: e.target.value,
                            }}
                        })
                    }
                }
                showBigEditIcon={props.showBigEditIcon}
                isFirstNameVisible={props.isFirstNameVisible}
                isMiddleNameVisible={props.isMiddleNameVisible}
                isLastNameVisible={props.isLastNameVisible}
                isFirstNameEdit={props.isFirstNameEdit}
                isMiddleNameEdit={props.isMiddleNameEdit}
                isLastNameEdit={props.isLastNameEdit}
            />
        }
    }

    return (
        <div className='editable-user-field'>
            {getCustomFieldEditInput()}
        </div>
    )
}

export default EditableUserField;

EditableUserField.defaultProps = {
    name: '',
    value: null,
    type: undefined,
    field: undefined,
    built_in_custom_field_id: undefined,
    options: [],
    optionColors: {},
    isEdit: false,
    showBigEditIcon: false,
    placeholder: '',
    prefix: '',
    suffix: '',
    disabledTextColor: undefined,
    editIcon: undefined,
    showToday: true,
    onEdit: () => { },
}

