                        setValue(value);
                        props.onEdit(props.id, value, () => {}, () => {setValue(props.value)})
                    }}
                    disabled={!props.isEdit}
                    showBigEditIcon={props.showBigEditIcon}
                />
            );
        }
    }

    return (
        <div  className='editable-custom-field'>
            <div className='custom-field-header'>
                <FontAwesomeIcon icon={['fas', convertIconFormatFromDB(props.icon)]} />
