89	        [fieldTypesConstants.TEXT, fieldTypesConstants.NUMBER].includes(userFieldType) ||
90	        builtinFieldKey === USER_ENTITY_FIELDS.EMAIL) {
91	        const isTextArea = customFieldType === fieldTypesConstants.TEXT_AREA;
92	        const numberOfRows = isTextArea ? 3 : 1;
93	        // Preserve HTML5 email validation for the built-in email user field
94	        const _type = builtinFieldKey === USER_ENTITY_FIELDS.EMAIL
95	            ? 'email'
96	            : getTextFieldTypeByCustomFieldType(isCustomField ? customFieldType : userFieldType);
97	        fieldNode = (
