import React from 'react';

import { LabeledDatePicker, isEmptyValue, calculateAge } from "@ob-love/ui";
import { LabeledAddressField } from "@ob-love/ui";
import { LabeledDropdown } from "@ob-love/ui";
import { LabeledPhoneNumber } from "@ob-love/ui";
import { LabeledUpload } from "@ob-love/ui";
import { LabeledToggleButton } from "@ob-love/ui";
import { convertYesNoValueToBoolean } from '../CustomField/helpers';
import { generateRangeFilterOptions, generateFootInchesHeightOptions } from '../QueryFilter/helpers';
import dayjs from 'dayjs';
import { LabeledTextField } from "@ob-love/ui";
import { generateOptionsFromEnum, getOptionsYesNo } from '../../helpers';
import { getTextFieldTypeByCustomFieldType } from '../../store/system/helpers';
import { UPLOAD_TYPE_PHOTO, USER_ENTITY_FIELDS, MAXIMUM_MULTISELECT_TOGGLE_OPTIONS } from '../../constants';
import i18n from '../../i18n';
import { Tooltip } from '@mui/material';
import { calculateAgeYoungerUpperLimit, validateAndUpdateRangeFields } from '../User/helpers';
import { getFormPageFieldLabel, isFormPageFieldUserField } from './helpers';

export const renderFormField = (field, options) => {
    const {
        formValues,
        fieldTypesConstants,
        systemStore,
        organizationStore,
        searchBoundaries,
        PHOTO_TYPE_MAP,
        // Styles
        inputStyle = {},
        inputVariant = 'outlined',
        phoneNumberInputStyle = {},
        fieldsLabelStyle = {},
        labeledContentWrapStyle = {},
        toggleButtonStyle = {},
        // Handlers
        onFieldChange,
        onDateChange,
        onDropdownCustomFieldChange,
        onAddressFill,
        onPhotoUpload,
        // Additional props
        canvasRef,
        birthdayError = false,
        isHiddenField = false,
        tooltip = '',
    } = options;

    const isCustomField = !!field.custom_field_id;
    const isUserField = isFormPageFieldUserField(field, systemStore.constants);
    const metaData = isCustomField ? field.custom_field_meta_data : field.meta_data;
    let required = isCustomField ? field.custom_field_meta_data?.required_on_form : field.user_field_meta_data?.required_on_form;
    const fieldLabel = getFormPageFieldLabel(field, isUserField);
    const placeholder = i18n.t((isCustomField ? field.custom_field_meta_data?.placeholder : null) || fieldLabel);
    const fieldInstructions = isCustomField ? field.custom_field_meta_data?.instructions : '';
    const infoTooltip = fieldInstructions ? i18n.t(fieldInstructions) : '';
    const isHideLabel = isHiddenField || field.meta_data?.is_hide_label || false;
    const builtinFieldKey = field.user_field_label;
    const key = isCustomField ? field.custom_field_id : builtinFieldKey;
    const value = isEmptyValue(formValues[key]?.value) ? field.value : formValues[key]?.value;
    const customFieldType = field.custom_field_type;
    const userFieldType = field.user_field_type;
    const is_lgbtq = organizationStore.organizationDetails?.is_lgbtq;

    let fieldNode = <></>;

    // Phone Number Field
    if (customFieldType === fieldTypesConstants.PHONE_NUMBER) {
        fieldNode = (
            <LabeledPhoneNumber
                inputStyle={phoneNumberInputStyle}
                labelStyle={fieldsLabelStyle}
                placeholder={placeholder}
                value={value}
                onChange={(value) => onFieldChange(field.custom_field_id, value, isCustomField)}
                label={i18n.t(fieldLabel)}
                required={required}
                infoTooltip={infoTooltip}
                contentWrapStyle={labeledContentWrapStyle}
                isHideLabel={isHideLabel}
                variant={inputVariant}
                isLineMode={inputVariant === 'standard'}
            />
        );
    }

    // Text, Number, TextArea Fields
    if ([fieldTypesConstants.TEXT, fieldTypesConstants.NUMBER, fieldTypesConstants.TEXT_AREA].includes(customFieldType) ||
        [fieldTypesConstants.TEXT, fieldTypesConstants.NUMBER].includes(userFieldType) ||
        builtinFieldKey === USER_ENTITY_FIELDS.EMAIL) {
        const isTextArea = customFieldType === fieldTypesConstants.TEXT_AREA;
        const numberOfRows = isTextArea ? 3 : 1;
        // Preserve HTML5 email validation for the built-in email user field
        const _type = builtinFieldKey === USER_ENTITY_FIELDS.EMAIL
            ? 'email'
            : getTextFieldTypeByCustomFieldType(isCustomField ? customFieldType : userFieldType);
        fieldNode = (
            <LabeledTextField
                key={`field_${key}`}
                name={field.id}
                label={i18n.t(fieldLabel)}
                value={value}
                placeholder={placeholder}
                required={required}
                infoTooltip={infoTooltip}
                type={_type}
                multiline={isTextArea}
                rows={numberOfRows}
                minRows={numberOfRows}
                maxRows={numberOfRows}
                inputStyle={inputStyle}
                labelStyle={fieldsLabelStyle}
                onChange={(e) => onFieldChange(key, e.target.value, isCustomField)}
                contentWrapStyle={labeledContentWrapStyle}
                isHideLabel={isHideLabel}
                variant={inputVariant}
            />
        );
    }

    // Date Field
    if (userFieldType === fieldTypesConstants.DATE || customFieldType === fieldTypesConstants.DATE || builtinFieldKey === USER_ENTITY_FIELDS.BIRTHDAY) {
        let maxDate;
        if (key === USER_ENTITY_FIELDS.BIRTHDAY) {
            maxDate = dayjs().subtract(18, 'year');
        }
        const valueData = typeof value === 'object' ? value : dayjs.unix(value);
        fieldNode = (
            <LabeledDatePicker
                key={`field_${key}`}
                required={required}
                label={i18n.t(fieldLabel)}
                value={valueData}
                onChange={(value) => onDateChange(isCustomField, field, value)}
                inputStyle={inputStyle}
                labelStyle={fieldsLabelStyle}
                maxDate={maxDate}
                showToday={key !== USER_ENTITY_FIELDS.BIRTHDAY}
                error={key === USER_ENTITY_FIELDS.BIRTHDAY ? birthdayError : false}
                infoTooltip={infoTooltip}
                contentWrapStyle={labeledContentWrapStyle}
                isHideLabel={isHideLabel}
                disabled={isHiddenField}
                variant={inputVariant}
            />
        );
    }

    // Address Field
    if (customFieldType === fieldTypesConstants.ADDRESS) {
        fieldNode = (
            <LabeledAddressField
                key={`field_${field.custom_field_id}`}
                label={i18n.t(fieldLabel)}
                street_address={formValues[field.custom_field_id]?.value?.street_address}
                city={formValues[field.custom_field_id]?.value?.city}
                state={formValues[field.custom_field_id]?.value?.state}
                country={formValues[field.custom_field_id]?.value?.country}
                zip_code={formValues[field.custom_field_id]?.value?.zip_code}
                hiddenFields={field.custom_field_meta_data?.hidden_address_fields || []}
                onChange={(e) => onAddressFill(e, field.custom_field_id)}
                required={required}
                infoTooltip={infoTooltip}
                inputStyle={inputStyle}
                labelStyle={fieldsLabelStyle}
                contentWrapStyle={labeledContentWrapStyle}
                isHideLabel={isHideLabel}
                variant={inputVariant}
            />
        );
    }

    // Dropdown and Multi-Select Fields
    if ([fieldTypesConstants.DROPDOWN, fieldTypesConstants.MULTI_SELECT].includes(customFieldType) ||
        [USER_ENTITY_FIELDS.GENDER, USER_ENTITY_FIELDS.GENDER_IDENTITY, USER_ENTITY_FIELDS.HEIGHT].includes(builtinFieldKey) ||
        userFieldType === fieldTypesConstants.YES_NO) {
        let menuItems;

        if (builtinFieldKey === USER_ENTITY_FIELDS.GENDER) {
            if (is_lgbtq) {
                required = false;
            }
            menuItems = [
                { value: systemStore.constants.gender.MALE, name: i18n.t('enums.gender.male') },
                { value: systemStore.constants.gender.FEMALE, name: i18n.t('enums.gender.female') },
            ];
        }

        if (builtinFieldKey === USER_ENTITY_FIELDS.GENDER_IDENTITY) {
            menuItems = generateOptionsFromEnum(systemStore.constants.gender_identity, 'enums.genderIdentity');
        }

        if (builtinFieldKey === USER_ENTITY_FIELDS.HEIGHT) {
            const filterOptionsFunc = organizationStore.organizationDetails.measurement_unit === systemStore.constants.measurement_unit?.METRIC
                ? generateRangeFilterOptions(55, 270, false, false, i18n.t('general.cm'))
                : generateFootInchesHeightOptions(55, 270, false);
            menuItems = filterOptionsFunc;
        }

        if (userFieldType === fieldTypesConstants.YES_NO) {
            menuItems = getOptionsYesNo('name');
        }

        if ([fieldTypesConstants.DROPDOWN, fieldTypesConstants.MULTI_SELECT].includes(customFieldType)) {
            const options = field.custom_field_meta_data?.options || [];
            menuItems = options.map(option => ({ value: option, name: option }));
        }

        const onChangeCallback = isCustomField ? onDropdownCustomFieldChange : onFieldChange;
        const _value = isCustomField && customFieldType === fieldTypesConstants.MULTI_SELECT ? value || [] : value;

        // Multi-select with <= 10 options: render as toggle buttons
        const customFieldOptionCount = field.custom_field_meta_data?.options?.length || 0;
        if (isCustomField && customFieldType === fieldTypesConstants.MULTI_SELECT && customFieldOptionCount <= MAXIMUM_MULTISELECT_TOGGLE_OPTIONS) {
            const toggleOptions = menuItems.map(option => ({ value: option.value, name: option.name }));
            fieldNode = (
                <LabeledToggleButton
                    key={`field_${key}`}
                    label={i18n.t(fieldLabel)}
                    toggleButtons={toggleOptions}
                    onChange={(newValue) => onChangeCallback(key, newValue, isCustomField, metaData || {})}
                    initialValue={_value}
                    exclusive={false}
                    required={required}
                    infoTooltip={infoTooltip}
                    contentWrapStyle={labeledContentWrapStyle}
                    isHideLabel={isHideLabel}
                    toggleButtonStyle={toggleButtonStyle}
                    labelStyle={fieldsLabelStyle}
                />
            );
        } else {
            fieldNode = (
                <LabeledDropdown
                    key={`field_${key}`}
                    label={i18n.t(fieldLabel)}
                    menuItems={menuItems}
                    value={_value}
                    placeholder={placeholder}
                    onChange={(e) => onChangeCallback(key, e.target.value, isCustomField, metaData || {})}
                    required={required}
                    infoTooltip={infoTooltip}
                    multiple={isCustomField ? customFieldType === fieldTypesConstants.MULTI_SELECT : false}
                    inputStyle={{...inputStyle, width: '100%'}}
                    labelStyle={fieldsLabelStyle}
                    contentWrapStyle={labeledContentWrapStyle}
                    isHideLabel={isHideLabel}
                    variant={inputVariant}
                />
            );
        }
    }

    // Partner Age / Partner Height range sub-fields (rendered as dependent dropdowns)
    const RANGE_SUB_FIELDS = [
        USER_ENTITY_FIELDS.AGE_YEARS_YOUNGER,
        USER_ENTITY_FIELDS.AGE_YEARS_OLDER,
        USER_ENTITY_FIELDS.AGE_FROM,
        USER_ENTITY_FIELDS.AGE_TO,
        USER_ENTITY_FIELDS.HEIGHT_FROM_CM,
        USER_ENTITY_FIELDS.HEIGHT_TO_CM,
    ];
    if (RANGE_SUB_FIELDS.includes(builtinFieldKey)) {
        const fieldPairs = [
            { from: USER_ENTITY_FIELDS.AGE_YEARS_YOUNGER, to: USER_ENTITY_FIELDS.AGE_YEARS_OLDER },
            { from: USER_ENTITY_FIELDS.AGE_FROM, to: USER_ENTITY_FIELDS.AGE_TO },
            { from: USER_ENTITY_FIELDS.HEIGHT_FROM_CM, to: USER_ENTITY_FIELDS.HEIGHT_TO_CM },
        ];
        const onRangeFieldChange = (newValue) => {
            onFieldChange(key, newValue, false);
            const currentValues = {
                [USER_ENTITY_FIELDS.AGE_YEARS_YOUNGER]: formValues[USER_ENTITY_FIELDS.AGE_YEARS_YOUNGER]?.value,
                [USER_ENTITY_FIELDS.AGE_YEARS_OLDER]: formValues[USER_ENTITY_FIELDS.AGE_YEARS_OLDER]?.value,
                [USER_ENTITY_FIELDS.AGE_FROM]: formValues[USER_ENTITY_FIELDS.AGE_FROM]?.value,
                [USER_ENTITY_FIELDS.AGE_TO]: formValues[USER_ENTITY_FIELDS.AGE_TO]?.value,
                [USER_ENTITY_FIELDS.HEIGHT_FROM_CM]: formValues[USER_ENTITY_FIELDS.HEIGHT_FROM_CM]?.value,
                [USER_ENTITY_FIELDS.HEIGHT_TO_CM]: formValues[USER_ENTITY_FIELDS.HEIGHT_TO_CM]?.value,
            };
            const rangeUpdates = validateAndUpdateRangeFields(key, newValue, currentValues, fieldPairs);
            Object.keys(rangeUpdates).forEach(dependentField => {
                onFieldChange(dependentField, null, false);
            });
        };

        let menuItems;
        if (builtinFieldKey === USER_ENTITY_FIELDS.AGE_YEARS_YOUNGER) {
            let upperLimit = searchBoundaries.AGE_YOUNGER_MAX;
            if (formValues[USER_ENTITY_FIELDS.BIRTHDAY]?.value) {
                const age = calculateAge(formValues[USER_ENTITY_FIELDS.BIRTHDAY]?.value?.toDate?.());
                upperLimit = calculateAgeYoungerUpperLimit(age, searchBoundaries);
            }
            menuItems = generateRangeFilterOptions(searchBoundaries.AGE_YOUNGER_MIN, upperLimit, false, false, i18n.t('general.years'));
        } else if (builtinFieldKey === USER_ENTITY_FIELDS.AGE_YEARS_OLDER) {
            menuItems = generateRangeFilterOptions(searchBoundaries.AGE_OLDER_MIN, searchBoundaries.AGE_OLDER_MAX, false, false, i18n.t('general.years'));
        } else if (builtinFieldKey === USER_ENTITY_FIELDS.AGE_FROM) {
            menuItems = generateRangeFilterOptions(searchBoundaries.AGE_FROM_MIN, searchBoundaries.AGE_FROM_MAX, false, false, i18n.t('general.years'));
        } else if (builtinFieldKey === USER_ENTITY_FIELDS.AGE_TO) {
            menuItems = generateRangeFilterOptions(searchBoundaries.AGE_TO_MIN, searchBoundaries.AGE_TO_MAX, false, false, i18n.t('general.years'));
        } else {
            const generateHeightOptions = organizationStore.organizationDetails.measurement_unit === systemStore.constants.measurement_unit?.METRIC
                ? generateRangeFilterOptions
                : generateFootInchesHeightOptions;
            menuItems = generateHeightOptions(55, 270, false, false, i18n.t('general.cm'));
        }

        fieldNode = (
            <LabeledDropdown
                key={`field_${key}`}
                label={i18n.t(fieldLabel)}
                menuItems={menuItems}
                value={value}
                placeholder={placeholder}
                onChange={(e) => onRangeFieldChange(e.target.value)}
                required={required}
                inputStyle={{...inputStyle, width: '100%'}}
                labelStyle={fieldsLabelStyle}
                contentWrapStyle={labeledContentWrapStyle}
                isHideLabel={isHideLabel}
                variant={inputVariant}
            />
        );
    }

    // Photo Upload Field
    if (userFieldType === fieldTypesConstants.PHOTO) {
        // Use field.id as the per-slot key so multiple fields with the same photo type
        // (e.g. two "other" slots) each get their own entry in formValues.photos.
        const photoKey = field.id;
        const _required = formValues.photos?.[photoKey]?.value ? false : required;
        fieldNode = (
            <>
                <LabeledUpload
                    label={`${i18n.t('general.upload')} ${i18n.t(fieldLabel)}`}
                    onChange={onPhotoUpload.bind(null, builtinFieldKey, photoKey)}
                    fileTypes={UPLOAD_TYPE_PHOTO}
                    fileName={formValues.photos?.[photoKey]?.fileName}
                    labelStyle={fieldsLabelStyle}
                    name={`photo_${photoKey}`}
                    required={_required}
                    key={`photo_upload_${photoKey}`}
                    contentWrapStyle={labeledContentWrapStyle}
                    isHideLabel={isHideLabel}
                    mode={inputVariant === 'standard' ? LabeledUpload.MODE.LINE : LabeledUpload.MODE.BOX}
                />
                <canvas ref={canvasRef} style={{ display: 'none' }} key={`photo_canvas_${photoKey}`} />
            </>
        );
    }

    // Yes/No Toggle Field
    if (customFieldType === fieldTypesConstants.YES_NO) {
        let _value = convertYesNoValueToBoolean(value);
        fieldNode = (
            <LabeledToggleButton
                label={i18n.t(fieldLabel)}
                toggleButtons={getOptionsYesNo()}
                onChange={(newValue) => onFieldChange(key, newValue, isCustomField)}
                initialValue={_value}
                required={required}
                infoTooltip={infoTooltip}
                contentWrapStyle={labeledContentWrapStyle}
                isHideLabel={isHideLabel}
                toggleButtonStyle={toggleButtonStyle}
                labelStyle={fieldsLabelStyle}
            />
        );
    }

    // Orientation Field — only rendered for LGBTQ-enabled orgs; non-LGBTQ orgs
    // fall back to organization.default_orientation server-side.
    if (is_lgbtq && builtinFieldKey === USER_ENTITY_FIELDS.ORIENTATION) {
        const menuItems = generateOptionsFromEnum(systemStore.constants.user_orientation, 'enums.userOrientation');
        fieldNode = (
            <LabeledDropdown
                key={`field_${key}`}
                label={i18n.t(fieldLabel)}
                menuItems={menuItems}
                value={value}
                placeholder={placeholder}
                onChange={(e) => onFieldChange(key, e.target.value, false)}
                required={required}
                inputStyle={{...inputStyle, width: '100%'}}
                labelStyle={fieldsLabelStyle}
                contentWrapStyle={labeledContentWrapStyle}
                isHideLabel={isHideLabel}
                variant={inputVariant}
            />
        );
    }

    return (
        <Tooltip title={tooltip}>

            <div>{fieldNode}</div>

        </Tooltip>
    )
};

