import EmptyValueFallbackRenderer from '../../../components/EmptyValueFallbackRenderer/EmptyValueFallbackRenderer';
import { Skeleton } from '@mui/material';
import { COLUMN_SELECTION_CATEGORIES } from '../helpers';
import i18n from '../../../i18n';
import { Tag, formatPrefixedId, isNullOrUndefined, formatPhoneDisplay } from "@ob-love/ui";
import constants from '@ob-love/ui/styles/constants.scss';
import './CustomField.scss';
import { buildAddressCustomFieldValue, CUSTOM_FIELD_PREFIX_STR, getEditableCustomFieldTypes } from '../../../components/CustomField/helpers';
import { TAG_TRANSPARENCY } from '../../../constants';
import EditableCustomFieldCell from './EditableCustomFieldCell';

export const CUSTOM_FIELD_MIN_WIDTH = 100;
export const CUSTOM_FIELD_MIN_WIDTH_SMALL = 100;

export const CustomField = (id, headerName, isBuiltInField, fieldType, systemConstants, minWidth = CUSTOM_FIELD_MIN_WIDTH, enableInlineEditing = false, customFieldData = null) => {
  headerName = isBuiltInField ? i18n.t(headerName) : headerName;

  // Only allow editing for these field types
  const EDITABLE_FIELD_TYPES = getEditableCustomFieldTypes();

  const isEditableFieldType = EDITABLE_FIELD_TYPES.includes(fieldType);
  const shouldUseEditableRenderer = enableInlineEditing && isEditableFieldType;

  return {
    field: formatPrefixedId(id, CUSTOM_FIELD_PREFIX_STR),
    headerName,
    headerTooltip: headerName,
    width: 350,
    minWidth,
    cellClass: 'ag-cell-class custom-field-cell-class',
    headerClass: 'table-header custom-field-header',
    category: COLUMN_SELECTION_CATEGORIES.CUSTOM_FIELD,
    hide: true,
    sortable: true,
    suppressRowClickSelection: shouldUseEditableRenderer,
    cellRenderer: shouldUseEditableRenderer ? (params) => (
      <EditableCustomFieldCell
        {...params}
        fieldType={fieldType}
        systemConstants={systemConstants}
        customFieldData={customFieldData}
        customFieldId={id}
      />
    ) : ((params) => {
      if(params.data === undefined) {
        return <Skeleton width={40} variant="text"/>
      }

      const customField = params.data.custom_fields?.find(element => id === element.custom_field_id);
      let element = customField?.value;
      if(!isNullOrUndefined(element)){
        if(fieldType === systemConstants.field_type.DROPDOWN || fieldType === systemConstants.field_type.MULTI_SELECT) {
          const value =  customField?.value;
          if (Array.isArray(value)) {
            if (value && customField?.target_meta_data?.colors && customField?.target_meta_data?.colors.length > 0) {
              element = [];
              value.forEach((val, index) => {
                let tagColor = constants.COLOR_WHITE;
                if (
                  Array.isArray(customField?.target_meta_data?.colors) &&
                  index >= 0 &&
                  index < customField.target_meta_data.colors.length
                ) {
                  tagColor = customField.target_meta_data.colors[index];
                }
                if(tagColor.toLowerCase() !== constants.COLOR_WHITE.toLowerCase() && tagColor.toLowerCase() !== constants.COLOR_WHITE_SHORT.toLowerCase()) {
                    element.push(
                        <Tag
                            key={`tag-${index}`}
                            width={'fit-content'}
                            color={tagColor}
                            height='auto'
                            minHeight={constants.SIZE_30}
                            backgroundColor={`${tagColor}${TAG_TRANSPARENCY}`}
                        >
                            {val}
                        </Tag>
                    )
                } else {
                    if (index === 0) {
                      element.push(val);
                    } else {
                      element.push(`, ${val}`);
                    }
                }
              });
            } else {
              element = customField?.value?.join(', ');
            }
          }
        }
        if(fieldType === systemConstants.field_type.ADDRESS) {
          element = buildAddressCustomFieldValue(customField?.value);
        }
        if(fieldType === systemConstants.field_type.YES_NO && !isNullOrUndefined(customField?.value)) {
          element = customField?.value ? i18n.t('yes') : i18n.t('no');
        }
        if(fieldType === systemConstants.field_type.PHONE_NUMBER) {
          element = formatPhoneDisplay(customField?.value);
        }
      }
      return (
        <EmptyValueFallbackRenderer>
          {element}
        </EmptyValueFallbackRenderer>
      );
    }),
  }
};

