import React from 'react';
import { CUSTOM_FIELD_PREFIX_STR } from '../../../components/CustomField/helpers';
import EditableUserField from '../../../components/User/EditableUserField/EditableUserField';
import './EditableCustomFieldCell.scss';
import { useSystemStore } from '../../../store/system/systemStore';
import constants from '@ob-love/ui/styles/constants.scss';
import { formatPrefixedId } from '@ob-love/ui';

const EditableCustomFieldCell = (props) => {
  const systemConstants = useSystemStore.getState().constants;

  if (props.data === undefined) {
    return null;
  }

  const customField = props.data.custom_fields?.find(element => props.customFieldId === element.custom_field_id);
  const fieldKey = formatPrefixedId(props.customFieldId, CUSTOM_FIELD_PREFIX_STR);
  const userId = props.data.id;
  if (props.customFieldData?.type === systemConstants.field_type.DROPDOWN) {
    if (customField?.value && Array.isArray(customField?.value)) {
      customField.value = customField.value.join(', ');
    }
  }
  return (
    <div className="editable-custom-field-cell">
      <EditableUserField
        field={fieldKey}
        type={props.fieldType}
        value={customField?.value}
        options={props.customFieldData?.meta_data?.options || []}
        optionColors={props.customFieldData?.meta_data?.colors || {}}
        isEdit={true}
        onEdit={(field, value, metaData, successCallback, errorCallback) => {
          if (props.onUpdateUserField) {
            props.onUpdateUserField(userId, field, value, metaData, successCallback, errorCallback);
          }
        }}
        placeholder={props.customFieldData?.label}
        built_in_custom_field_id={props.customFieldData?.built_in_custom_field_id}
        showBigEditIcon={false}
        disabledTextColor={constants.COLOR_GREY_20}
      />
    </div>
  );
};

export default EditableCustomFieldCell;

EditableCustomFieldCell.defaultProps = {
  data: undefined,
  fieldType: '',
  systemConstants: {},
  customFieldData: {},
  customFieldId: '',
  onUpdateUserField: () => {},
};

