import { useLayoutEffect } from "react"
import { useParams } from "react-router-dom";
import FormRegisterForm from "./FormRegisterForm";
import { usePublicFormStore } from "../../store/publicForm/publicFormStore";
import { PUBLIC_ID_HEADER_NAME } from "../../constants";
import NetworkPublic from "../../networkPublic/networkPublic";

const FormPublicEdit = (props) => {
    const publicFormStore = usePublicFormStore((state) => state);

    const { user_public_uuid, form_unique_id } = useParams();

    useLayoutEffect(() => {
    if (user_public_uuid) {
        NetworkPublic.addRequestHeader(PUBLIC_ID_HEADER_NAME, user_public_uuid);
    }}, [user_public_uuid]);

    const onUpdateUserField = (field, value, metaData = {}) => {
        publicFormStore.updateFormValue(
            form_unique_id,
            field,
            value,
            metaData,
            () => { },
            () => { },
        )
    }

    let renderContent = (
            <FormRegisterForm
                isResumable={true}
                onUpdateUserField={onUpdateUserField}
            />
        )
    return renderContent;
}

export default FormPublicEdit;

