import React, { useState } from 'react';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';

import './EditableCustomField.scss';
import { useSystemStore } from '../../../store/system/systemStore';
import i18n from '../../../i18n';
import { EditableDropdown } from "@ob-love/ui";
import { EditableTextfield } from "@ob-love/ui";
import { getTextFieldTypeByCustomFieldType } from '../../../store/system/helpers';
import { convertIconFormatFromDB, getOptionsYesNo } from '../../../helpers';
import EditableDate from '../../EditableDate/EditableDate';
import { buildCustomFieldDropdownColorOptions } from '../helpers';
import { buildAddressCustomFieldValue, convertYesNoValueToBoolean } from '../../CustomField/helpers';

const EditableCustomField = (props) => {
    const systemConstants = useSystemStore((state) => state.constants);
    const isMultiSelect = props.type === systemConstants.field_type.MULTI_SELECT;
    const [isEdit, setIsEdit] = useState(false);
    const [value, setValue] = useState(isMultiSelect ? props.value || [] : props.value);

    const isBuiltInField = !!props.built_in_custom_field_id;
    const isDropDown = systemConstants.field_type.DROPDOWN === props.type;
    let fieldValue = isBuiltInField && isDropDown ? i18n.t(`customFields.${value}`, {defaultValue: ''}) : value;

    const onSubmit = (e) => {
        e && e.preventDefault();
        let _value = value;

        if (_value !== props.value) {
            if (
                props.type === systemConstants.field_type.NUMBER &&
                _value !== '' && _value !== null && _value !== undefined &&
                Number.isNaN(parseFloat(_value))
            ) {
                setValue(props.value);
                setIsEdit(!isEdit);
                return;
            }

            let meta_data = {};

            if (props.type === systemConstants.field_type.DROPDOWN || props.type === systemConstants.field_type.MULTI_SELECT) {
                meta_data = buildCustomFieldDropdownColorOptions(value, props.dropDownOptions, props.dropdownColorOptions);
            }

            props.onEdit(props.id, _value, () => {}, () => { setValue(props.value) }, meta_data);
        }

        setIsEdit(!isEdit);
    };

    const getCustomFieldEditInput = () => {
        const fieldType = getTextFieldTypeByCustomFieldType(props.type);
        if(fieldType !== null) {
            const isAddress = props.type === systemConstants.field_type.ADDRESS;
            const placeholder = props.placeholder ? i18n.t(props.placeholder) : i18n.t('users.customFieldNotFilled');
            if (isAddress && fieldValue) {
                fieldValue = buildAddressCustomFieldValue(fieldValue);
            }
            const isNumber = fieldType === 'number';
            return (
                <form onSubmit={onSubmit}>
                    <EditableTextfield
                        key={`cf_edit_${props.id}`}
                        placeholder={placeholder}
                        type={fieldType}
                        defaultValue={fieldValue ? fieldValue : ''}
                        value={fieldValue ? fieldValue : ''}
                        onBlur={onSubmit}
                        onChange={(e) => {
                            setValue(e.target.value)}
                        }
                        multiline={!isNumber}
                        maxRows={isNumber ? undefined : 10}
                        disabled={!props.isEdit || isAddress}
                        showBigEditIcon={props.showBigEditIcon}
                    />
                </form>
            )
        } else if (
            props.type === systemConstants.field_type.DROPDOWN || 
            props.type === systemConstants.field_type.MULTI_SELECT ||
            props.type === systemConstants.field_type.YES_NO
        ) {
            let options = [];
            let displayConstantPropsValue = !props.isEdit;
            if (props.type === systemConstants.field_type.YES_NO) {
                options = getOptionsYesNo('name')
                fieldValue = convertYesNoValueToBoolean(value);
                displayConstantPropsValue = false;
            } else {
                options = props.dropDownOptions.map(option => ({value: option, name: option}))
            }
            const placeholder = props.placeholder ? props.placeholder : i18n.t('users.customFieldNotFilled');
            return (
                <EditableDropdown
                    placeholder={placeholder}
                    defaultValue={fieldValue}
                    value={fieldValue}
                    options={options}
                    onChange={(e) => {setValue(e.target.value)}}
                    onBlur={onSubmit}
                    disabled={!props.isEdit}
                    displayConstantPropsValue={displayConstantPropsValue}
                    multiple={props.type === systemConstants.field_type.MULTI_SELECT}
                    showBigEditIcon={props.showBigEditIcon}
                />
            );
        } else if (props.type === systemConstants.field_type.DATE) {
            const _value = value ? parseInt(value) : null;
            const placeholder = props.placeholder ? props.placeholder : i18n.t('users.customFieldNotFilled');
            return (
                <EditableDate
                    placeholder={placeholder}
                    defaultValue={_value}
                    value={_value}
                    onChange={(value) => {
                        setValue(value);
                        props.onEdit(props.id, value, () => {}, () => {setValue(props.value)})
                    }}
                    disabled={!props.isEdit}
                    showBigEditIcon={props.showBigEditIcon}
                />
            );
        }
    }

    return (
        <div  className='editable-custom-field'>
            <div className='custom-field-header'>
                <FontAwesomeIcon icon={['fas', convertIconFormatFromDB(props.icon)]} />
                <div className='custom-field-name'>{i18n.t(`${props.name}`)}</div>
            </div>
            <div className='custom-field-value-wrap'>
                {getCustomFieldEditInput()}
            </div>
        </div>
    )
}

export default EditableCustomField;

EditableCustomField.defaultProps = {
    name: '',
    value: null,
    type: undefined,
    id: undefined,
    built_in_custom_field_id: undefined,
    dropDownOptions: [],
    dropdownColorOptions: {},
    isEdit: true,
    showBigEditIcon: false,
    onEdit: () => {},
    placeholder: '',
}

