@view_public_form.route('/api/public/form/field/<int:custom_field_id>', methods=['PUT'])
@RequireLogin([User.UserStatus.WAIT_APPROVAL])
@HandleException()
def update_user_custom_field_value(custom_field_id):
    data = request_body_dict(request)
    value = data.get('value')
    form_unique_id = data.get('form_unique_id')
    public_user_id = request.environ.get('user').u_id
    update_target_meta_data = data.get('meta_data', {})
    assert public_user_id and (value is not None) and custom_field_id
    return response_json(objective_love_core_lib.user_custom_field.update_target_value(
        public_user_id,
        custom_field_id,
        value,
        filter_target_meta_data={
            TargetCustomFieldMetaDataField.FORM_UNIQUE_ID.value: form_unique_id,
        },
        update_target_meta_data=update_target_meta_data,
        is_updated_by_user=True
    ))


